const items = $input.all();

return items.map((it) => {
  const { payload, driver, trip, recent_decisions, recent_trips } = it.json;

  const systemPrompt =
    "You are a fraud detection AI for a ride-hailing platform. " +
    "Analyze driver complaints about unpaid trips. Use the provided context " +
    "(driver profile, trip details, complaint history) to assess if the complaint " +
    "is legitimate, fraudulent, or uncertain. " +
    "Return STRICT JSON only — no markdown fencing, no prose. " +
    "Schema: {verdict: 'fraud'|'legitimate'|'uncertain', risk_score: number 0-1, " +
    "reasoning: short string, key_factors: [strings]}. " +
    "risk_score: 0=clearly legitimate, 1=clearly fraud.";

  const driverProfile = {
    account_status: driver?.account_status,
    flags: driver?.flags,
    total_trips: driver?.total_trips,
    history: driver?.history,
  };

  const userPrompt = [
    `Complaint: "${payload.complaint_text}"`,
    `Claimed amount: ${payload.claimed_amount ?? "n/a"}`,
    "",
    "Trip:",
    JSON.stringify(trip, null, 2),
    "",
    "Driver profile:",
    JSON.stringify(driverProfile, null, 2),
    "",
    "Recent decisions for this driver (last 5):",
    JSON.stringify(recent_decisions ?? [], null, 2),
    "",
    "Recent trips for this driver (last 5):",
    JSON.stringify(recent_trips ?? [], null, 2),
  ].join("\n");

  const hashInput = [
  payload.driver_id || '',
  payload.trip_id || '',
  payload.claimed_amount ?? '',
  (payload.complaint_text || '').toLowerCase().trim().replace(/\s+/g, ' '),
  driver?.account_status || 'unknown',
  (driver?.flags || []).slice().sort().join(','),
  driver?.history?.fraud_count_lifetime ?? 0,
].join('|');

  return {
    json: {
      ...it.json,
      _prompt: {
        system: systemPrompt,
        user: userPrompt,
      },
      _hash_input: hashInput,
    },
  };
});

const items = $input.all();
const promptItems = $('Merge').all();

return items.map((it, idx) => {
  const ctx = promptItems[idx]?.json || {};
  const parsed = it.json.output;

  const cbState = it.json._cb_after?.state || it.json._cb?.state || null;
  const cbTripReason = it.json._cb_after?.trip_reason || null;

  if (!parsed || typeof parsed !== 'object') {
    return wrap(ctx, {
      verdict: null,
      source: 'ai-empty-content',
      reasoning: 'LLM Chain returned no structured output',
      risk_score: null,
      key_factors: [],
    }, cbState, cbTripReason);
  }

  return wrap(ctx, {
    verdict: parsed.verdict,
    source: 'ai',
    reasoning: parsed.reasoning,
    risk_score: parsed.risk_score,
    key_factors: parsed.key_factors || [],
  }, cbState, cbTripReason);
});

function wrap(ctx, aiDecision, cbState, cbTripReason) {
  return {
    json: {
      msg_id: ctx.msg_id,
      request_id: ctx.request_id,
      enqueued_at: ctx.enqueued_at,
      payload: ctx.payload,
      driver: ctx.driver,
      trip: ctx.trip,
      _content_hash: ctx._content_hash,
      ai_decision: aiDecision,
      ai_meta: {
        model: null,
        tokens: { input: null, output: null, total: null },
        cb: {
          state: cbState,
          trip_reason: cbTripReason,
        },
      },
    },
  };
}

const items = $input.all();
return items.map((it) => {
  const cached = JSON.parse(it.json._cached_raw);
  return {
    json: {
      msg_id: it.json.msg_id,
      request_id: it.json.request_id,
      enqueued_at: it.json.enqueued_at,
      payload: it.json.payload,
      driver: it.json.driver,
      trip: it.json.trip,
      ai_decision: {
        verdict: cached.verdict,
        source: 'ai-cache',
        reasoning: cached.reasoning,
        risk_score: cached.risk_score,
        key_factors: cached.key_factors,
      },
      ai_meta: {
        model: cached.model,
        tokens: { input: 0, output: 0, total: 0, cached: true },
      },
    },
  };
});

const items = $input.all();
