return items.map((it, idx) => {
  const ctx = promptItems[idx]?.json || {};
  const rawError = it.json?.error;
  const errMsg = (typeof rawError === 'string')
    ? rawError
    : String(rawError?.message || rawError?.name || 'unknown_error');

  const cbState = it.json._cb_after?.state || it.json._cb?.state || null;
  const cbTripReason = it.json._cb_after?.trip_reason || null;

  return {
    json: {
      msg_id: ctx.msg_id,
      request_id: ctx.request_id,
      enqueued_at: ctx.enqueued_at,
      payload: ctx.payload,
      driver: ctx.driver,
      trip: ctx.trip,
      _content_hash: ctx._content_hash,
      ai_decision: {
        verdict: null,
        source: 'ai-unavailable',
        reasoning: `Both LLM providers failed: ${errMsg.slice(0, 200)}`,
        risk_score: null,
        key_factors: [],
      },
      ai_meta: {
        model: null,
        tokens: { input: null, output: null, total: null },
        cb: { state: cbState, trip_reason: cbTripReason },
      },
    },
  };
});

const LUA_CB_CHECK = `
local key = KEYS[1]
local now = tonumber(ARGV[1])
local window_ms = tonumber(ARGV[2])

local data = redis.call('HMGET', key, 'state', 'cooldown_until_ms', 'window_started_ms')
local state = data[1] or 'closed'
local cooldown_until_ms = tonumber(data[2]) or 0
local window_started_ms = tonumber(data[3]) or now

-- open → half_open if cooldown elapsed
if state == 'open' and now >= cooldown_until_ms then
  state = 'half_open'
  redis.call('HMSET', key,
    'state', 'half_open',
    'success_count', 0,
    'failure_count', 0,
    'window_started_ms', now)
end

-- reset closed window if expired
if state == 'closed' and (now - window_started_ms) > window_ms then
  redis.call('HMSET', key,
    'success_count', 0,
    'failure_count', 0,
    'window_started_ms', now)
end

redis.call('EXPIRE', key, 600)

local allow = 1
if state == 'open' then allow = 0 end

return {state, allow}
`;

const CB_KEY = 'fraud:cb:openrouter';
const WINDOW_MS = 30000;

const item = $input.first();

const Redis = require('ioredis');
const redis = new Redis({
  host: 'redis',
  port: 6379,
  connectTimeout: 5000,
  commandTimeout: 5000,
  maxRetriesPerRequest: 1,
});

try {
  const [state, allowFlag] = await redis.eval(
    LUA_CB_CHECK,
    1,
    CB_KEY,
    String(Date.now()),
    String(WINDOW_MS),
  );

  await redis.quit();

  return [{
    json: {
      ...item.json,
      _cb: {
        state,
        allow: allowFlag === 1,
      },
    },
  }];
} catch (err) {
  try { await redis.quit(); } catch {}
  // fail-open: не блокуємо pipeline якшо зламалось
  return [{
    json: {
      ...item.json,
      _cb: {
        state: 'unknown',
        allow: true,
        error: String(err.message || err),
      },
    },
  }];
}

const LUA_CB_REPORT = `
local key = KEYS[1]
local outcome = ARGV[1]
local now = tonumber(ARGV[2])
local trip_reason = ARGV[3]
local retry_after_ms = tonumber(ARGV[4]) or 0
local min_sample = tonumber(ARGV[5])
local failure_threshold = tonumber(ARGV[6])
local baseline_cooldown = tonumber(ARGV[7])
local max_cooldown = tonumber(ARGV[8])

local data = redis.call('HMGET', key,
  'state', 'success_count', 'failure_count', 'consecutive_open_count')
local state = data[1] or 'closed'
local success_count = tonumber(data[2]) or 0
local failure_count = tonumber(data[3]) or 0
local consecutive_open_count = tonumber(data[4]) or 0

if outcome == 'success' then
  success_count = success_count + 1
else
  failure_count = failure_count + 1
end

local new_state = state
local cooldown_until_ms = 0
local trip_now = ''

local function compute_cooldown()
  if trip_reason == '429' and retry_after_ms > 0 then
    if retry_after_ms > baseline_cooldown then return retry_after_ms end
    return baseline_cooldown
  end
  local backoff = baseline_cooldown * (2 ^ (consecutive_open_count - 1))
  if backoff > max_cooldown then return max_cooldown end
  return backoff
end

if state == 'closed' then
  local total = success_count + failure_count
  if total >= min_sample and (failure_count / total) >= failure_threshold then
    new_state = 'open'
    consecutive_open_count = consecutive_open_count + 1
    cooldown_until_ms = now + compute_cooldown()
    success_count = 0
    failure_count = 0
    trip_now = trip_reason
  end
elseif state == 'half_open' then
  if outcome == 'failure' then
    new_state = 'open'
    consecutive_open_count = consecutive_open_count + 1
    cooldown_until_ms = now + compute_cooldown()
    success_count = 0
    failure_count = 0
    trip_now = trip_reason
  else
    new_state = 'closed'
    consecutive_open_count = 0
    success_count = 0
    failure_count = 0
  end
end

redis.call('HMSET', key,
  'state', new_state,
  'success_count', success_count,
  'failure_count', failure_count,
  'cooldown_until_ms', cooldown_until_ms,
  'consecutive_open_count', consecutive_open_count,
  'last_trip_reason', trip_now,
  'last_update_ms', now)

  if new_state ~= state then
    redis.call('HSET', key, 'window_started_ms', now)
  end
redis.call('EXPIRE', key, 600)

return {new_state, trip_now}
`;

const CB_KEY = 'fraud:cb:openrouter';
const MIN_SAMPLE = 20;
const FAILURE_THRESHOLD = 0.5;
const BASELINE_COOLDOWN_MS = 30000;
const MAX_COOLDOWN_MS = 300000;

const item = $input.first();

// error может прийти строкой ("Authorization failed...") или объектом — обрабатываем оба
const rawError = item.json?.error;
const errObj = (rawError && typeof rawError === 'object') ? rawError : {};
const errMsg = (typeof rawError === 'string')
  ? rawError
  : String(errObj?.message || errObj?.name || errObj?.code || 'unknown_error');

const statusCode =
  errObj?.statusCode ||
  errObj?.status ||
  errObj?.response?.status ||
  errObj?.cause?.status ||
  null;

let tripReason = 'unknown';
let retryAfterMs = 0;

if (statusCode === 429 || /\b429\b|rate.?limit|too.?many/i.test(errMsg)) {
  tripReason = '429';
  const retryAfterRaw =
    errObj?.headers?.['retry-after'] ||
    errObj?.response?.headers?.['retry-after'] ||
    errObj?.responseHeaders?.['retry-after'] ||
    null;
  if (retryAfterRaw) {
    const parsed = parseInt(retryAfterRaw, 10);
    if (!isNaN(parsed) && parsed > 0) retryAfterMs = parsed * 1000;
  }
} else if ((statusCode && statusCode >= 500 && statusCode < 600) || /\b5\d{2}\b|server.?error|service.?unavailable/i.test(errMsg)) {
  tripReason = '5xx';
} else if (/timeout|ETIMEDOUT|ECONNRESET|ENOTFOUND/i.test(errMsg)) {
  tripReason = 'timeout';
} else if (statusCode === 401 || statusCode === 403 || /authoriz|unauthorized|forbidden|api.?key|credential/i.test(errMsg)) {
  tripReason = 'auth';
} else {
  tripReason = '5xx';
}

const Redis = require('ioredis');
const redis = new Redis({
  host: 'redis',
  port: 6379,
  connectTimeout: 5000,
  commandTimeout: 5000,
  maxRetriesPerRequest: 1,
});

try {
  const [newState, currentTripReason] = await redis.eval(
    LUA_CB_REPORT,
    1,
    CB_KEY,
    'failure',
    String(Date.now()),
    tripReason,
    String(retryAfterMs),
    String(MIN_SAMPLE),
    String(FAILURE_THRESHOLD),
    String(BASELINE_COOLDOWN_MS),
    String(MAX_COOLDOWN_MS),
  );
  await redis.quit();

  return [{
    json: {
      ...item.json,
      _cb_after: {
        state: newState,
        trip_reason: currentTripReason || tripReason,
      },
      _llm_error: {
        statusCode: statusCode || null,
        retry_after_ms: retryAfterMs,
        message: errMsg.slice(0, 200),
      },
    },
  }];
} catch (err) {
  try { await redis.quit(); } catch {}
  return [{
    json: {
      ...item.json,
      _cb_after: { state: 'unknown', error: String(err.message || err) },
    },
  }];
}
